+/// Find the closest preset for a given ratio (used when cycling presets).
+fn preset_for_ratio(ratio: f32) -> DockPreset {
+    let presets = [
+        DockPreset::Compact,
+        DockPreset::Third,
+        DockPreset::Balanced,
+        DockPreset::Half,
+        DockPreset::Wide,
+    ];
+    let mut best = DockPreset::Balanced;
+    let mut best_diff = f32::MAX;
+    for p in presets {
+        let diff = (p.ratio() - ratio).abs();
+        if diff < best_diff {
+            best = p;
+            best_diff = diff;
+        }
+    }
+    best
+}
